#!/usr/bin/env node
// Lightweight Conventional Commits check (no external dependency).
// Usage: node scripts/check-commit-msg.mjs <path-to-commit-msg-file>
import fs from "node:fs";

const file = process.argv[2];
if (!file) process.exit(0);

const raw = fs.readFileSync(file, "utf8");
const header = raw.split("\n").find((l) => l.trim() && !l.startsWith("#")) ?? "";

// Allow merge/revert/fixup autogenerated headers.
if (/^(Merge|Revert|fixup!|squash!)/.test(header)) process.exit(0);

const TYPES = [
  "feat",
  "fix",
  "docs",
  "style",
  "refactor",
  "perf",
  "test",
  "build",
  "ci",
  "chore",
  "revert",
];

const re = new RegExp(`^(${TYPES.join("|")})(\\([\\w.\\-/*]+\\))?!?: .{1,}`);

if (!re.test(header)) {
  console.error("\n✖ Commit message must follow Conventional Commits.");
  console.error(`  Got:      "${header}"`);
  console.error("  Expected: <type>(optional-scope): <subject>");
  console.error(`  Types:    ${TYPES.join(", ")}`);
  console.error("  Example:  feat(components): add Combobox multiselect\n");
  process.exit(1);
}

if (header.length > 100) {
  console.error(`\n✖ Commit header too long (${header.length} > 100 chars).\n`);
  process.exit(1);
}
